final:
module top_module (
    input d,
    input q,
    input u,
    output reg obf_a
);
    always @(*) begin
        case ({d, q, u})
            3'b011: obf_a = 1'b1;
            3'b000: obf_a = 1'b0;
            3'b010: obf_a = 1'b1;
            3'b100: obf_a = 1'b0;
            3'b101: obf_a = 1'b0;
            3'b110: obf_a = 1'b1;
            3'b001: obf_a = 1'b0;
            3'b111: obf_a = 1'b1;
        endcase
    end
endmodule
